func (s *ScoringMixin) SelectCohort(candidates []*ScoredChunk, queryEmbedding []float32, k int) []*ScoredChunk {
	if len(candidates) == 0 {
		return nil
	}

	q := normalize(queryEmbedding)
	dim := len(q)

	type entry struct {
		sc       *ScoredChunk
		unit     []float32 // nil if embedding unavailable or wrong dim
		relevance float32
	}
	entries := make([]entry, 0, len(candidates))
	priorities := make([]float32, 0, len(candidates))

	for _, sc := range candidates {
		raw := s.getEmbedding(sc.ChunkID)
		var unit []float32
		var rel float32
		if raw != nil && len(raw) == dim {
			unit = normalize(raw)
			rel = dot(q, unit)
		}
		entries = append(entries, entry{sc: sc, unit: unit, relevance: rel})
		pri, ok := s.Priority[sc.Provenance]
		if !ok {
			pri = 0.5
		}
		priorities = append(priorities, float32(pri))
	}

	remaining := make([]int, len(entries))
	for i := range remaining {
		remaining[i] = i
	}

	var selUnits [][]float32
	var result []*ScoredChunk
	n := k
	if len(remaining) < n {
		n = len(remaining)
	}

	for iter := 0; iter < n; iter++ {
		bestScore := float32(math.Inf(-1))
		bestJ := 0

		for j, i := range remaining {
			rel := entries[i].relevance
			pri := priorities[i]
			unit := entries[i].unit

			var coverage float32
			if len(selUnits) > 0 {
				var maxSim float32
				if unit != nil {
					for _, su := range selUnits {
						if sim := dot(su, unit); sim > maxSim {
							maxSim = sim
						}
					}
				}
				coverage = rel - float32(s.Lambda)*maxSim
			} else {
				coverage = rel
			}

			composite := s.Rw*rel + s.Pw*pri + s.Cw*coverage
			if composite > bestScore {
				bestScore = composite
				bestJ = j
			}
		}

		chosenI := remaining[bestJ]
		remaining = append(remaining[:bestJ], remaining[bestJ+1:]...)
		sc := entries[chosenI].sc
		sc.Score = float64(bestScore)
		sc.Embedding = nil
		if entries[chosenI].unit != nil {
			selUnits = append(selUnits, entries[chosenI].unit)
		} else {
			selUnits = append(selUnits, make([]float32, dim))
		}
		result = append(result, sc)
	}

	return result
}

