func (g *GraphMixin) GraphTraverseHops(ents []string) (map[string]struct{}, int) {
	entsSet := make(map[string]struct{}, len(ents))
	for _, e := range ents {
		entsSet[e] = struct{}{}
	}

	hop1 := make(map[string]struct{})
	svoCount := 0

	for _, entityID := range ents {
		for _, triple := range g.relationshipIndex.GetObjects(entityID) {
			hop1[triple.ObjectID] = struct{}{}
			svoCount++
		}
		for _, triple := range g.relationshipIndex.GetSubjects(entityID) {
			hop1[triple.SubjectID] = struct{}{}
			svoCount++
		}
	}
	for e := range entsSet {
		delete(hop1, e)
	}

	hop2 := make(map[string]struct{})
	for entityID := range hop1 {
		for _, triple := range g.relationshipIndex.GetObjects(entityID) {
			hop2[triple.ObjectID] = struct{}{}
		}
		for _, triple := range g.relationshipIndex.GetSubjects(entityID) {
			hop2[triple.SubjectID] = struct{}{}
		}
	}
	for e := range entsSet {
		delete(hop2, e)
	}
	for e := range hop1 {
		delete(hop2, e)
	}

	result := make(map[string]struct{}, len(hop1)+len(hop2))
	for e := range hop1 {
		result[e] = struct{}{}
	}
	for e := range hop2 {
		result[e] = struct{}{}
	}
	return result, svoCount
}

