func (e *EnhancedSearch) ExpandEntity(
	pool map[string]*ScoredChunk,
	nsChunkIDs map[string]struct{},
	queryEmbedding []float32,
) (map[string]struct{}, []string) {
	expandedEntityIDs := make(map[string]struct{})
	var added []string

	if !e.entity || e.entityIndex == nil {
		return expandedEntityIDs, added
	}

	var queryVecFlat []float32
	if e.laneEntityMinSim != nil {
		queryVecFlat = queryEmbedding
	}

	poolKeys := make([]string, 0, len(pool))
	for k := range pool {
		poolKeys = append(poolKeys, k)
	}

	for _, cid := range poolKeys {
		for _, entityPair := range e.entityIndex.GetEntitiesForChunk(cid) {
			entityID := entityPair.EntityID
			expandedEntityIDs[entityID] = struct{}{}
			for _, linkedPair := range e.entityIndex.GetChunksForEntity(entityID, e.entityTopN) {
				linkedChunkID := linkedPair.ChunkID
				if nsChunkIDs != nil {
					if _, ok := nsChunkIDs[linkedChunkID]; !ok {
						continue
					}
				}
				if _, inPool := pool[linkedChunkID]; !inPool {
					if queryVecFlat != nil {
						emb := e.getEmbedding(linkedChunkID)
						if emb != nil && cosineSimilarity(queryVecFlat, emb) < *e.laneEntityMinSim {
							continue
						}
					}
					chunk := e.fetchChunk(linkedChunkID)
					if chunk != nil {
						pool[linkedChunkID] = &ScoredChunk{
							ChunkID:    linkedChunkID,
							Chunk:      chunk,
							Score:      0.0,
							Provenance: "entity_adjacent",
							LinkedBy:   entityID,
						}
						added = append(added, linkedChunkID)
					}
				}
			}
		}
	}
	return expandedEntityIDs, added
}

