def store_svo_triples(self, triples: list, namespace: str | None = None) -> int:
    if not triples:
        return 0
    self._ensure_connection()
    rows = []
    for t in triples:
        ns = namespace
        if ns is None and t.source_chunk_id:
            with self._pgconn.cursor() as cur:
                cur.execute(
                    f"SELECT namespace FROM {self._table} WHERE chunk_id = %s",
                    [t.source_chunk_id],
                )
                row = cur.fetchone()
                ns = row[0] if row else None
        rows.append((
            t.source_chunk_id, t.subject_id, t.verb, t.object_id,
            float(t.confidence), ns,
        ))
    with self._pgconn.cursor() as cur:
        for row in rows:
            cur.execute(
                "INSERT INTO svo_triples (chunk_id, subject_id, verb, object_id, confidence, namespace) "
                "VALUES (%s, %s, %s, %s, %s, %s)",
                row,
            )
    self._pgconn.commit()
    return len(rows)

